// // This module is designed to capture the value of the input signal 'pm' on the falling edge of the clock signal 'clk', and store it for later access via the output 'rndout'.
module top_module(pm,clk,rndout);input [63:0] pm; 
input clk; 
output [63:0] rndout; 
reg [63:0] t;



always @(posedge clk) 
begin
 t <= pm; 
end 
assign rndout=t;

endmodule
